```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>
#include <algorithm>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the span for zero-copy operations
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream from the adaptor
    hexi::binary_stream stream(adaptor);

    // Read the header fields using the stream
    PacketHeader header;
    stream >> header.version >> header.flags >> header.packet_id;

    return header;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the span for zero-copy operations
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream from the adaptor
    hexi::binary_stream stream(adaptor);

    // Find the null terminator position
    auto data_span = stream.span(); // Get remaining data as span
    auto null_pos = std::find(data_span.begin(), data_span.end(), 0);

    if (null_pos == data_span.end()) {
        // No null terminator found, return entire buffer
        return std::string_view(reinterpret_cast<const char*>(buffer.data()), buffer.size());
    }

    // Calculate length until null terminator
    size_t length = std::distance(data_span.begin(), null_pos);

    // Use view() for zero-copy string extraction
    auto string_view = stream.view(length);

    // Advance past the null terminator
    stream.advance_read(1);

    return string_view;
}
```

