Looking at the code fragments, I can see that Hexi provides `buffer_adaptor` for buffer operations. Based on the usage patterns shown in the examples, here's the implementation:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a read-only buffer adaptor from the source buffer
    hexi::buffer_adaptor adaptor(source_buffer);

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor);

    // Determine how many bytes we can actually read (don't read past buffer end)
    size_t actual_bytes_to_read = std::min(bytes_to_read, source_buffer.size());

    // Create result vector and read the data
    std::vector<uint8_t> result(actual_bytes_to_read);
    if (actual_bytes_to_read > 0) {
        stream.read(result.data(), actual_bytes_to_read);
    }

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a writable buffer adaptor from the destination buffer
    hexi::buffer_adaptor adaptor(dest_buffer);

    // Create a binary stream for writing
    hexi::binary_stream stream(adaptor);

    // Write the source data to the destination buffer
    if (!source_data.empty()) {
        stream.write(source_data.data(), source_data.size());
    }
}
```

