// Helper function to create test buffer for floats
std::vector<uint8_t> create_float_buffer(const std::vector<float>& items) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    uint8_t data_type = 1;
    uint32_t count = static_cast<uint32_t>(items.size());
    stream << data_type << count << items;

