```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer adaptor for the vector
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream with no_throw to handle errors without exceptions
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Check if there's enough space for header + items
    // Header is uint32_t (4 bytes), items require space for size + each element
    std::size_t required_space = sizeof(uint32_t); // header

    // Calculate space needed for items (varint size + each uint32_t)
    required_space += hexi::varint_size(items.size()); // size field as varint
    required_space += items.size() * sizeof(uint32_t); // each item

    // Check available write space
    if (adaptor.write_available() < required_space) {
        return false; // Insufficient space
    }

    // Get write pointer and write data
    stream.put(header); // Write header

    // Write container using write_container (or put for containers)
    stream.write_container(items);

    // Check if write was successful
    return static_cast<bool>(stream);
}
```

