    auto buffer2 = create_tls_buffer();

    std::vector<uint8_t> data1 = {10, 20, 30};
    std::vector<uint8_t> data2 = {40, 50, 60};

    buffer1.write(data1.data(), data1.size());
    buffer2.write(data2.data(), data2.size());

    EXPECT_EQ(data1.size(), buffer1.size());
    EXPECT_EQ(data2.size(), buffer2.size());
}

TEST(TLSBuffer, WriteLargeData) {
    auto buffer = create_tls_buffer();
    std::vector<uint8_t> data(2000, 0xAA);

    buffer.write(data.data(), data.size());

    EXPECT_EQ(data.size(), buffer.size());
}

