#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator that can hold up to element_count uint64_t elements
    block_allocator<uint64_t, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " elements\n\n";

    // Demonstrate allocation pattern that shows LIFO behavior (stack-like free list)
    std::cout << "1. Allocating " << element_count << " blocks:\n";
    std::array<uint64_t*, element_count> blocks{};

    // Allocate all available blocks
    for (size_t i = 0; i < element_count; ++i) {
        blocks[i] = allocator.allocate();
        *blocks[i] = i + 1; // Store some data
        std::cout << "   Allocated block " << i << " with value: " << *blocks[i] << "\n";
    }

    std::cout << "\n2. Deallocating blocks in order 0, 2, 4 (showing free list push operations):\n";

    // Deallocate some blocks - these get pushed onto the free list
    allocator.deallocate(blocks[0]);
    std::cout << "   Deallocated block 0 (pushed to free list head)\n";

    allocator.deallocate(blocks[2]);
    std::cout << "   Deallocated block 2 (pushed to free list head)\n";

    allocator.deallocate(blocks[4]);
    std::cout << "   Deallocated block 4 (pushed to free list head)\n";

    std::cout << "\n3. Allocating 3 new blocks (showing free list pop operations - LIFO order):\n";

    // Allocate blocks - these should come from free list in LIFO order
    auto* new1 = allocator.allocate();
    *new1 = 100;
    std::cout << "   Allocated new block with value: " << *new1 << " (should come from block 4's memory)\n";

    auto* new2 = allocator.allocate();
    *new2 = 200;
    std::cout << "   Allocated new block with value: " << *new2 << " (should come from block 2's memory)\n";

    auto* new3 = allocator.allocate();
    *new3 = 300;
    std::cout << "   Allocated new block with value: " << *new3 << " (should come from block 0's memory)\n";

    std::cout << "\n4. Demonstrating free list is now empty:\n";

    // Try to allocate one more than available
    try {
        auto* extra = allocator.allocate();
        std::cout << "   Unexpectedly allocated extra block!\n";
        allocator.deallocate(extra);
    } catch (const std::bad_alloc&) {
        std::cout << "   Correctly failed to allocate - free list is empty\n";
    }

    std::cout << "\n5. Cleaning up remaining allocations:\n";

    // Deallocate all remaining blocks
    for (size_t i = 0; i < element_count; ++i) {
        if (i != 0 && i != 2 && i != 4) { // Skip already deallocated blocks
            allocator.deallocate(blocks[i]);
