However, looking more closely at the Hexi library patterns, I notice that it uses a concept-based approach. Here's a more idiomatic implementation that follows Hexi's style:

```cpp
#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<std::endian from, std::endian to, typename T>
T convert_endianness(T value) {
    if constexpr (from == to) {
        return value;
    } else {
        // Use Hexi's conditional_reverse approach for arithmetic types
        if constexpr (std::is_arithmetic_v<T>) {
            if constexpr (std::is_same_v<T, float>) {
                return std::bit_cast<T>(std::byteswap(std::bit_cast<std::uint32_t>(value)));
            } else if constexpr (std::is_same_v<T, double>) {
                return std::bit_cast<T>(std::byteswap(std::bit_cast<std::uint64_t>(value)));
            } else {
                return std::byteswap(value);
            }
        } else {
            // For non-arithmetic types, use byte-by-byte reversal
            auto bytes = reinterpret_cast<const char*>(&value);
            T result;
            auto result_bytes = reinterpret_cast<char*>(&result);

            for (size_t i = 0; i < sizeof(T); ++i) {
                result_bytes[i] = bytes[sizeof(T) - 1 - i];
            }

            return result;
        }
    }
}

template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    if (from == to) {
        return value;
    }

    // Use the compile-time version with runtime check
    if (from == std::endian::little && to == std::endian::big) {
        return convert_endianness<std::endian::little, std::endian::big, T>(value);
    } else if (from == std::endian::big && to == std::endian::little) {
        return convert_endianness<std::endian::big, std::endian::little, T>(value);
    } else if (from == std::endian::native && to == std::endian::little) {
        return convert_endianness<std::endian::native, std::endian::little, T>(value);
    } else if (from == std::endian::native && to == std::endian::big) {
        return convert_endianness<std::endian::native, std::endian::big, T>(value);
    } else if (from == std::endian::little && to == std::endian::native) {
        return convert_endianness<std::endian::little, std::endian::native, T>(value);
    } else if (from == std::endian::big && to == std::endian::native) {
        return convert_endianness<std::endian::big, std::endian::native, T>(value);
