```cpp
#include <hexi/pmc/stream_base.h>
#include <hexi/shared.h>

void clear_stream_state(hexi::pmc::stream_base& stream) {
    // Clear the stream state by setting it to ok
    stream.set_state(hexi::stream_state::ok);
}

void set_stream_error(hexi::pmc::stream_base& stream) {
    // Set the stream to error state using user_defined_err
    stream.set_state(hexi::stream_state::user_defined_err);
}

hexi::stream_state check_stream_state(const hexi::pmc::stream_base& stream) {
    // Return the current stream state
    return stream.state();
}
```

**Explanation:**

1. **`clear_stream_state`**: Uses the `set_state()` method to set the stream state to `stream_state::ok`, effectively clearing any error state.

2. **`set_stream_error`**: Uses the `set_state()` method to set the stream state to `stream_state::user_defined_err`, indicating an error condition.

3. **`check_stream_state`**: Returns the current stream state by calling the `state()` method on the stream object.

