#include <gtest/gtest.h>
#include <hexi/pmc/stream_base.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/shared.h>
#include <vector>

// Include the implementation
#include "implementation.hpp"

// Helper: Create a mock buffer for testing
class MockBuffer : public hexi::pmc::buffer_base {
    std::vector<std::byte> data_;
    bool empty_;
public:
    MockBuffer(size_t size, bool empty = false) : data_(size), empty_(empty) {}
    std::size_t size() const override { return data_.size(); }
    bool empty() const override { return empty_; }
};

TEST(StreamBase, GetStreamSize) {
    MockBuffer buffer(100);
    hexi::pmc::stream_base stream(buffer);

    size_t size = get_stream_size(stream);

    EXPECT_EQ(100, size);
}

TEST(StreamBase, IsStreamEmpty) {
    MockBuffer buffer(0, true);
    hexi::pmc::stream_base stream(buffer);

    bool is_empty = is_stream_empty(stream);

    EXPECT_TRUE(is_empty);
}

TEST(StreamBase, GetStreamStateInfo) {
    MockBuffer buffer(50, false);
    hexi::pmc::stream_base stream(buffer);

    auto info = get_stream_state_info(stream);

    EXPECT_EQ(hexi::stream_state::ok, info.state);
    EXPECT_EQ(50, info.buffer_size);
    EXPECT_FALSE(info.is_empty);
}

TEST(StreamBase, GetStreamStateInfoEmpty) {
    MockBuffer buffer(0, true);
    hexi::pmc::stream_base stream(buffer);

    auto info = get_stream_state_info(stream);

    EXPECT_EQ(hexi::stream_state::ok, info.state);
    EXPECT_EQ(0, info.buffer_size);
    EXPECT_TRUE(info.is_empty);
}

