    std::vector<std::byte> buffer(1000);
    hexi::pmc::buffer_adaptor adaptor(buffer, hexi::init_empty);

    hexi::pmc::buffer& buf_ref = adaptor;
    hexi::pmc::binary_stream_writer writer(static_cast<hexi::pmc::buffer_write&>(buf_ref));
    hexi::pmc::binary_stream_reader reader(static_cast<hexi::pmc::buffer_read&>(buf_ref));

    UserData original;
    original.user_id = 12345;
    original.name = "testuser";

    serialize_object(writer, original);

    UserData deserialized;
    deserialize_object(reader, deserialized);

    EXPECT_EQ(original.user_id, deserialized.user_id);
    EXPECT_EQ(original.name, deserialized.name);
}

TEST(PMCBinaryStream, SerialiseDeserialiseMultiple) {
