struct UserData {
    uint32_t user_id;
    std::string name;

    void serialise(auto& stream) {
        stream << user_id << name;
    }
};

void serialize_object(hexi::pmc::binary_stream_writer& writer, const UserData& data) {
    // Create a temporary buffer to hold the serialized data
    std::vector<std::byte> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Create a binary stream for writing
    hexi::pmc::binary_stream stream(adaptor);

    // Serialize the data using its serialise method
    const_cast<UserData&>(data).serialise(stream);

    // Write the size of the serialized data first, then the data itself
    writer << static_cast<uint32_t>(buffer.size());
    writer.write_bytes(buffer.data(), buffer.size());
}

void deserialize_object(hexi::pmc::binary_stream_reader& reader, UserData& data) {
    // Read the size of the serialized data
    uint32_t data_size;
    reader >> data_size;

    // Read the serialized data into a buffer
    std::vector<std::byte> buffer(data_size);
    reader.read_bytes(buffer.data(), data_size);

    // Create a buffer adaptor and binary stream for reading
    hexi::pmc::buffer_adaptor adaptor(buffer);
    hexi::pmc::binary_stream stream(adaptor);

    // Deserialize the data using its serialise method
    data.serialise(stream);
}

