#include <gtest/gtest.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(BufferAdaptor, GetReadPointer) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t value = 12345;
    adaptor.write(&value, sizeof(value));

    const void* ptr = get_read_pointer(adaptor);

    EXPECT_NE(nullptr, ptr);
    EXPECT_EQ(reinterpret_cast<const uint32_t*>(ptr)[0], value);
}

TEST(BufferAdaptor, GetBufferState) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t value = 999;
    adaptor.write(&value, sizeof(value));

    auto state = get_buffer_state(adaptor);

    EXPECT_EQ(sizeof(value), state.size);
    EXPECT_NE(nullptr, state.read_ptr);
    EXPECT_FALSE(state.is_empty);
}

TEST(BufferAdaptor, GetBufferStateEmpty) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    auto state = get_buffer_state(adaptor);

    EXPECT_EQ(0, state.size);
    EXPECT_TRUE(state.is_empty);
}

TEST(BufferAdaptor, ReadPointerAdvances) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t val1 = 100, val2 = 200;
    adaptor.write(&val1, sizeof(val1));
    adaptor.write(&val2, sizeof(val2));

    const void* ptr1 = get_read_pointer(adaptor);

    uint32_t read_val = 0;
    adaptor.read(&read_val, sizeof(read_val));

    const void* ptr2 = get_read_pointer(adaptor);

    EXPECT_NE(ptr1, ptr2);
    EXPECT_EQ(reinterpret_cast<const uint8_t*>(ptr2) - reinterpret_cast<const uint8_t*>(ptr1), sizeof(uint32_t));
}

