```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

const void* get_read_pointer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Get the current read pointer by accessing the underlying data
    // Since buffer_adaptor provides operator[] and we know it's a contiguous range,
    // we can get a pointer to the current read position
    if (buffer.empty()) {
        return nullptr;
    }
    return &buffer[0];  // Returns pointer to the first available byte
}

struct BufferState {
    std::size_t size;
    const void* read_ptr;
    bool is_empty;
};

BufferState get_buffer_state(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferState state;
    state.size = buffer.size();        // Get current buffer size (bytes available to read)
    state.read_ptr = get_read_pointer(buffer);  // Get current read pointer
    state.is_empty = buffer.empty();   // Check if buffer is empty
    return state;
}
```

