Looking at the code fragments, I can see that Hexi provides binary stream readers and writers that work with buffers. Here's the implementation of the varint encoding/decoding functions:

```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Handle negative values using zigzag encoding
    if constexpr (std::is_signed_v<T>) {
        // Zigzag encoding for signed integers
        value = (value << 1) ^ (value >> (sizeof(T) * 8 - 1));
    }

    // Encode the value as varint
    while (value >= 0x80) {
        writer.write_byte(static_cast<std::uint8_t>((value & 0x7F) | 0x80));
        value >>= 7;
        bytes_written++;

        // Check if writer is still in good state
        if (writer.state() != stream_state::ok) {
            return bytes_written;
        }
    }

    // Write the final byte
    writer.write_byte(static_cast<std::uint8_t>(value & 0x7F));
    bytes_written++;

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T result = 0;
    int shift = 0;

    while (true) {
        // Check if reader is in good state before reading
        if (reader.state() != stream_state::ok) {
            return 0;
        }

        std::uint8_t byte = reader.read_byte();
        result |= static_cast<T>(byte & 0x7F) << shift;
        shift += 7;

        // If high bit is not set, this is the last byte
        if ((byte & 0x80) == 0) {
            break;
        }

        // Prevent shift overflow for the type
        if (shift >= static_cast<int>(sizeof(T) * 8)) {
            // This would overflow, set error state if possible
            if (reader.allow_throw()) {
                // In a real implementation, you might want to handle this differently
                return 0;
            }
            break;
        }
    }

    // Handle zigzag decoding for signed integers
    if constexpr (std::is_signed_v<T>) {
        result = (result >> 1) ^ -(result & 1);
    }

    return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Create writer and encode the value
    hexi::pmc::binary_stream_writer writer(adaptor);
    std::size_t bytes_written = encode_varint<T>(writer, original_value);

    // Check if encoding was successful
    if (writer.state() != stream_state::ok || bytes_written == 0) {
        return false;
    }

    // Create reader and decode the value
    hexi::pmc::binary_stream_reader reader(adaptor);
    T decoded_value = decode_varint<T>(reader);

    // Check if decoding was successful
    if (reader.state() != stream_state::ok) {
        return false;
    }

    // Compare with original value
    return original_value == decoded_value;
}
```

