class CustomBuffer : public hexi::pmc::buffer_base {
    std::vector<std::byte> data_;
    std::size_t read_pos_ = 0;
    std::size_t write_pos_ = 0;

public:
    // Required virtual methods from buffer_base
    std::size_t size() const override {
        return data_.size();
    }

    bool empty() const override {
        return data_.empty();
    }

    // buffer_read interface methods
    void read(void* destination, std::size_t length) override {
        if (read_pos_ + length > data_.size()) {
            // Handle read beyond buffer - you might want to throw an exception
            return;
        }

        std::byte* dest = static_cast<std::byte*>(destination);
        std::copy(data_.begin() + read_pos_, data_.begin() + read_pos_ + length, dest);
        read_pos_ += length;
    }

    void copy(void* destination, std::size_t length) const override {
        if (read_pos_ + length > data_.size()) {
            // Handle copy beyond buffer
            return;
        }

        std::byte* dest = static_cast<std::byte*>(destination);
        std::copy(data_.begin() + read_pos_, data_.begin() + read_pos_ + length, dest);
    }

    void skip(std::size_t length) override {
        read_pos_ = std::min(read_pos_ + length, data_.size());
    }

    const std::byte& operator[](const std::size_t index) const override {
        return data_[index];
    }

    std::size_t find_first_of(std::byte val) const override {
        auto it = std::find(data_.begin() + read_pos_, data_.end(), val);
        if (it != data_.end()) {
            return std::distance(data_.begin(), it);
        }
        return npos;
    }

    // buffer_write interface methods
    void write(const void* source, std::size_t length) override {
        const std::byte* src = static_cast<const std::byte*>(source);

        // If writing beyond current size, resize the vector
        if (write_pos_ + length > data_.size()) {
            data_.resize(write_pos_ + length);
        }

        std::copy(src, src + length, data_.begin() + write_pos_);
        write_pos_ += length;
    }

    void reserve(std::size_t length) override {
        data_.reserve(length);
    }

    bool can_write_seek() const override {
        return true;
    }

    void write_seek(buffer_seek direction, std::size_t offset) override {
        switch (direction) {
            case buffer_seek::beg:
                write_pos_ = std::min(offset, data_.size());
                break;
            case buffer_seek::cur:
                write_pos_ = std::min(write_pos_ + offset, data_.size());
                break;
            case buffer_seek::end:
                write_pos_ = data_.size() >= offset ? data_.size() - offset : 0;
                break;
        }
    }

    // buffer interface method (non-const operator[])
    std::byte& operator[](const std::size_t index) {
        return data_[index];
    }

    // Helper method to add data (for testing)
    void add_data(const void* source, std::size_t length) {
        const std::byte* bytes = static_cast<const std::byte*>(source);
        data_.insert(data_.end(), bytes, bytes + length);
        write_pos_ = data_.size(); // Update write position
    }

    // Helper method to clear data (for testing)
    void clear() {
        data_.clear();
        read_pos_ = 0;
        write_pos_ = 0;
    }

    // Additional helper methods
    std::size_t tell_read() const { return read_pos_; }
    std::size_t tell_write() const { return write_pos_; }

    void seek_read(std::size_t pos) {
        read_pos_ = std::min(pos, data_.size());
    }

    void seek_write(std::size_t pos) {
        write_pos_ = std::min(pos, data_.size());
    }
};
