TEST(PartialReadWrite, ReadWithSizeTracking) {
    std::vector<uint8_t> buffer = {10, 20, 30, 40, 50};
    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    // Check initial size
    EXPECT_EQ(5, read_adaptor.size());

    // Read 2 bytes
    uint8_t data[2];
    read_adaptor.read(data, 2);

    // Check remaining size
    EXPECT_EQ(3, read_adaptor.size());

    // Read remaining
    uint8_t remaining[3];
    read_adaptor.read(remaining, 3);

    // Check final size
    EXPECT_EQ(0, read_adaptor.size());
}

TEST(PartialReadWrite, WriteWithFreeTracking) {
    std::vector<uint8_t> buffer(100, 0);
    hexi::pmc::buffer_adaptor adaptor(buffer);

