    EXPECT_EQ(0, free_after_first); // For std::vector that auto-grows, free() is always 0 after write

    // Write second chunk
    std::vector<uint8_t> chunk2 = {4, 5};
    adaptor.write(chunk2.data(), chunk2.size());

    std::size_t free_after_second = adaptor.buffer_write_adaptor<std::vector<uint8_t>>::free();
    EXPECT_EQ(0, free_after_second); // For std::vector that auto-grows, free() is always 0 after write
}

