std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a write adaptor with an initially empty buffer
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    std::size_t total_written = 0;

    for (const auto& chunk : chunks) {
        if (chunk.empty()) {
            continue;
        }

        // Check available space before each write
        std::size_t available_space = adaptor.free();

        // Write the chunk (or as much as we can if space is limited)
        std::size_t to_write = (chunk.size() <= available_space) ? chunk.size() : available_space;
        if (to_write > 0) {
            adaptor.write(chunk.data(), to_write);
            total_written += to_write;
        }

        // If we couldn't write the entire chunk due to space constraints,
        // write the remaining data in the next iteration
        if (to_write < chunk.size()) {
            // For simplicity, we'll write the rest now, but in a real scenario
            // you might want to handle this differently
            std::size_t remaining = chunk.size() - to_write;
            adaptor.write(chunk.data() + to_write, remaining);
            total_written += remaining;
        }
    }

    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a read adaptor with the input buffer
    std::vector<uint8_t> mutable_buffer = buffer; // Create mutable copy
    hexi::pmc::buffer_read_adaptor adaptor(mutable_buffer);

    std::vector<uint8_t> result;

    // Continue reading until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read in this chunk
        std::size_t to_read = (chunk_size <= adaptor.size()) ? chunk_size : adaptor.size();

        // Create temporary buffer for this read
        std::vector<uint8_t> temp_buffer(to_read);

        // Read the data
        adaptor.read(temp_buffer.data(), to_read);

        // Append to result
        result.insert(result.end(), temp_buffer.begin(), temp_buffer.end());

        // Check remaining data after read
        std::size_t remaining = adaptor.size();
        if (remaining == 0) {
            break;
        }
    }

    return result;
}
