```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    // Verify we have enough data for the header
    if (adaptor.size() < sizeof(Header)) {
        throw std::runtime_error("Buffer too small for header");
    }

    // Use copy() to peek at header without advancing read cursor
    Header header;
    adaptor.copy(reinterpret_cast<std::byte*>(&header), sizeof(Header));

    // Use read_ptr() to verify pointer position hasn't changed
    const std::byte* ptr_before = adaptor.read_ptr();

    // Verify the data by checking magic number (example verification)
    if (header.magic != 0xDEADBEEF) { // Example magic number
        throw std::runtime_error("Invalid magic number in header");
    }

    // Verify read pointer hasn't moved after copy()
    const std::byte* ptr_after = adaptor.read_ptr();
    if (ptr_before != ptr_after) {
        throw std::runtime_error("Read cursor advanced during peek");
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    if (adaptor.empty()) {
        return {}; // Return empty vector if buffer is empty
    }

    // Use copy() to peek at first byte
    uint8_t first_byte;
    adaptor.copy(reinterpret_cast<std::byte*>(&first_byte), 1);

    std::vector<uint8_t> result;

    // Conditionally read based on the peeked value
    if (first_byte == 0x01) { // Example condition: if first byte is 0x01
        // Read all available data
        result.resize(adaptor.size());
        adaptor.read(reinterpret_cast<std::byte*>(result.data()), adaptor.size());
    } else if (first_byte == 0x02) { // Another condition: if first byte is 0x02
        // Read only first 4 bytes
        result.resize(4);
        adaptor.read(reinterpret_cast<std::byte*>(result.data()), 4);
    }
    // If condition not met, return empty vector

    return result;
}
```

