struct ProtocolPacket {
    uint32_t message_id;
    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Convert message_id to big-endian and write
    uint32_t be_message_id = hexi::endian::native_to_big(packet.message_id);
    stream.write(be_message_id);

    // Convert data_values elements to big-endian and write container
    std::vector<uint16_t> be_data_values;
    be_data_values.reserve(packet.data_values.size());
    for (const auto& value : packet.data_values) {
        be_data_values.push_back(hexi::endian::native_to_big(value));
    }
    stream.write_container(be_data_values);

    // Convert checksum to big-endian and write
    uint32_t be_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.write(be_checksum);

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    ProtocolPacket packet;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read message_id and convert from big-endian to native
    uint32_t be_message_id;
    stream.read(be_message_id);
    packet.message_id = hexi::endian::big_to_native(be_message_id);

    // Read data_values count and convert from big-endian to native
    uint32_t data_count;
    stream.read(data_count);
    data_count = hexi::endian::big_to_native(data_count);

    // Read data_values container and convert each element
    std::vector<uint16_t> be_data_values;
    stream.read_container(be_data_values, data_count);
    packet.data_values.reserve(be_data_values.size());
    for (const auto& value : be_data_values) {
        packet.data_values.push_back(hexi::endian::big_to_native(value));
    }

    // Read checksum and convert from big-endian to native
    uint32_t be_checksum;
    stream.read(be_checksum);
    packet.checksum = hexi::endian::big_to_native(be_checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    ProtocolHeader header;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span to get message_id without copying, then convert
    auto message_id_span = stream.span<uint32_t>(1);
