```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialize sensor_id directly
        adaptor(sensor_id);

        // Serialize temperatures with endianness conversion
        uint32_t temp_count = static_cast<uint32_t>(temperatures.size());
        adaptor(temp_count);

        for (const float& temp : temperatures) {
            float temp_le = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor(temp_le);
        }

        // Serialize pressure with endianness conversion
        double pressure_le = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor(pressure_le);
    }

    void serialise(auto& adaptor) {
        // Deserialize sensor_id directly
        adaptor(sensor_id);

        // Deserialize temperature count
        uint32_t temp_count;
        adaptor(temp_count);

        // Resize vector and deserialize temperatures with endianness conversion
        temperatures.resize(temp_count);
        for (float& temp : temperatures) {
            adaptor(temp);
            hexi::little_to_native_inplace(temp);
        }

        // Deserialize pressure with endianness conversion
        adaptor(pressure);
        hexi::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use the const serialise method for serialization
    data.serialise(stream);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData data;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use the non-const serialise method for deserialization
    data.serialise(stream);

    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use view to extract null-terminated sensor name if present
    info.sensor_name = stream.view('\0');

    // Use enforce_read_bounds to check if there's enough data for sensor_id
    stream.adaptor().enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream(info.sensor_id);

    // Skip remaining data
    stream.adaptor().skip(stream.adaptor().remaining());

    return info;
}
